//! ECDHE shared secret computation tests
//!
//! This module tests the [`compute_ecdhe_shared_secret`] function using
//! test vectors generated by Python's cryptography library.

use tls_decryptor::types::CurveType;
use tls_decryptor::util::compute_ecdhe_shared_secret;

use super::{hex_to_bytes, load_test_vectors};

#[test]
fn test_ecdhe_p256() {
    let vectors = load_test_vectors();
    let p256 = &vectors["ecdhe_test_vectors"]["p256"];

    let server_private_key = hex_to_bytes(p256["server_private_key"].as_str().unwrap());
    let client_public_key = hex_to_bytes(p256["client_public_key"].as_str().unwrap());
    let expected_shared_secret = hex_to_bytes(p256["shared_secret"].as_str().unwrap());

    let shared_secret = compute_ecdhe_shared_secret(
        &server_private_key,
        &client_public_key,
        CurveType::Secp256r1,
    )
    .expect("ECDHE P-256 computation failed");

    assert_eq!(
        shared_secret, expected_shared_secret,
        "P-256 shared secret does not match expected value"
    );
    assert_eq!(
        shared_secret.len(),
        32,
        "P-256 shared secret should be 32 bytes"
    );
}

