#[test]
fn test_ecdhe_p521_65byte_private_key() {
    // Test P-521 with 65-byte private key (when leading bit is 0)
    let vectors = load_test_vectors();
    let p521_65 = &vectors["ecdhe_test_vectors"]["p521_65byte"];

    let server_private_key = hex_to_bytes(p521_65["server_private_key"].as_str().unwrap());
    let client_public_key = hex_to_bytes(p521_65["client_public_key"].as_str().unwrap());
    let expected_shared_secret = hex_to_bytes(p521_65["shared_secret"].as_str().unwrap());

    // Verify the private key is 65 bytes
    assert_eq!(
        server_private_key.len(),
        65,
        "P-521 private key should be 65 bytes"
    );

    let shared_secret = compute_ecdhe_shared_secret(
        &server_private_key,
        &client_public_key,
        CurveType::Secp521r1,
    )
    .expect("ECDHE P-521 65-byte computation failed");

    assert_eq!(
        shared_secret, expected_shared_secret,
        "P-521 65-byte shared secret does not match expected value"
    );
    assert_eq!(
        shared_secret.len(),
        66,
        "P-521 shared secret should be 66 bytes"
    );
}

