#[test]
fn test_ecdhe_symmetric() {
    // Test that both directions compute the same shared secret
    let vectors = load_test_vectors();
    let p256 = &vectors["ecdhe_test_vectors"]["p256"];

    let server_private_key = hex_to_bytes(p256["server_private_key"].as_str().unwrap());
    let server_public_key = hex_to_bytes(p256["server_public_key"].as_str().unwrap());
    let client_private_key = hex_to_bytes(p256["client_private_key"].as_str().unwrap());
    let client_public_key = hex_to_bytes(p256["client_public_key"].as_str().unwrap());

    // Server computes shared secret using client's public key
    let server_shared = compute_ecdhe_shared_secret(
        &server_private_key,
        &client_public_key,
        CurveType::Secp256r1,
    )
    .expect("Server ECDHE computation failed");

    // Client computes shared secret using server's public key
    let client_shared = compute_ecdhe_shared_secret(
        &client_private_key,
        &server_public_key,
        CurveType::Secp256r1,
    )
    .expect("Client ECDHE computation failed");

    assert_eq!(
        server_shared, client_shared,
        "Server and client should compute the same shared secret"
    );
}
